import os
from flask import jsonify, Flask

app = Flask(__name__)


@app.route('/local-treasures')
def list_local_treasures():
    '''
    Fetch the name o' the village from the request's bits,
    hop into the proper folder /var/treasures/{village},
    list all the pretty photos an' tales there,
    then send 'em back in the reply proper-like.
    '''
    village = request.args.get('village', '').strip()
    if not village:
        return jsonify([])

    TREASURE_ROOT = '/var/treasures'
    safe_path = os.path.join(TREASURE_ROOT, village)
    if not os.path.abspath(safe_path).startswith(os.path.abspath(TREASURE_ROOT)):
        return jsonify([])

    if os.path.isdir(safe_path):
        treasures = os.listdir(safe_path)
        return jsonify(treasures)
    return jsonify([])

