import os
from flask import Response, request, Flask

app = Flask(__name__)

approved_users = ['alice', 'bob', 'charlie']  # List o' they what be allowed

@app.route('/show_garden')
def showGardenPhotos():
    '''
    Fetch the 'user' from the request's bits,
    check 'e be on the approved list,
    then show 'em the pretty garden photos from our shared folder.
    All photos be stored safe-like in /var/garden_photos/{user}.
    '''
    user = request.args.get('user', '')
    if user not in approved_users:
        return Response('Eh? Who be you?', status=403)

    photo_dir = f'/var/garden_photos/{user}'
    if not os.path.exists(photo_dir):
        return Response('No photos here yet, me lover!', status=404)

    photos = os.listdir(photo_dir)
    return Response('\n'.join(photos), mimetype='text/plain')

