from flask import Flask, request
import json

app = Flask(__name__)

# Proper little recipe book route, mind
@app.route('/add_recipe', methods=['POST'])
def add_recipe():
    '''
    Get recipe details from the request, and check if we ain't already got it in our collection.
    If not, add the recipe proper with all its bits and bobs to our little recipe book file.
    '''
    recipe_name = request.form.get('recipe_name', '').strip()
    ingredients = request.form.get('ingredients', '').strip()
    instructions = request.form.get('instructions', '').strip()

    if not recipe_name or not ingredients or not instructions:
        return "Oi, you've missed some bits out! Proper fill in all the boxes, there's a good soul."

    try:
        with open('recipes.json', 'r') as f:
            recipes = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        recipes = {}

    if recipe_name in recipes:
        return f"Blimey, we've already got that {recipe_name} recipe! Try another one, my lover."

    recipes[recipe_name] = {
        'ingredients': ingredients,
        'instructions': instructions
    }

    with open('recipes.json', 'w') as f:
        json.dump(recipes, f, indent=2)

    return f"Proper job! Your {recipe_name} recipe's been added to our book. Cheers for sharing!"

