from flask import request
import xml.etree.ElementTree as ET

# Load our lovely local cider orchards data, proper job
orchard_tree = ET.parse('orchards.xml')
root = orchard_tree.getroot()


@app.route('/orchard')
def orchard_info():
    '''
    Grab the orchard name from the request,
    make an XPath query (/orchards/orchard[@name=<orchard_name>]/variety) to find it in the XML root,
    return the list of cider apple varieties grown there. Proper West Country stuff!
    '''
    orchard_name = request.args.get('name')
    if not orchard_name:
        return "Oi, you bain't told us which orchard you'm after!", 400

    varieties = []
    for orchard in root.findall(f"./orchard[@name='{orchard_name}']"):
        for variety in orchard.findall('variety'):
            varieties.append(variety.text)

    return {"orchard": orchard_name, "varieties": varieties}

