from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Fetch the "theme" from the GET request proper,
    check if it be one o' they pre-set styles,
    if 'tis, then send 'em straight to the dashboard like.
    '''
    theme = request.GET.get('theme', '')
    if theme in ['light', 'dark', 'cornish_pasty']:
        return redirect('dashboard')
    return HttpResponse("Alright my lover, theme's all set!")

